{
  "schemaVersion": 3,
  "judgeId": "judge_2",
  "batchIndex": 8,
  "comparisons": [
    {
      "leftId": "dt_01_concept_02",
      "rightId": "dt_01_concept_09",
      "winnerId": "dt_01_concept_02",
      "reason": "Concept 02 có cơ chế 'cứu mẻ mắm hỏng' ở chương 1-3 rất kịch tính và bám sát chuyên môn vi sinh, tạo ra thành quả ngay lập tức cho gia đình. Concept 09 về muối có phần hơi đơn điệu trong việc phân loại thủ công, chưa tạo ra sự bứt phá về 'khoái hoạt' mạnh mẽ bằng việc khôi phục gia sản như 02."
    },
    {
      "leftId": "dt_01_concept_02",
      "rightId": "dt_01_concept_10",
      "winnerId": "dt_01_concept_02",
      "reason": "Concept 02 thực tế và phù hợp với bối cảnh cuối thập niên 1980 hơn. Concept 10 về du lịch trải nghiệm hơi xa lạ với tâm thế 'làm giàu bằng tay nghề' của độc giả nam tần thời kỳ này, khi mà cái ăn cái mặc vẫn là ưu tiên hàng đầu."
    },
    {
      "leftId": "dt_01_concept_03",
      "rightId": "dt_01_concept_04",
      "winnerId": "dt_01_concept_03",
      "reason": "Concept 03 tập trung vào ngư cụ (lưới) - linh hồn của nghề biển, cơ chế sửa chữa bằng kỹ thuật cơ khí rất thực tế và giải quyết nợ nần ngay chương 3. Concept 04 về rong biển hơi mang tính 'thực phẩm chức năng' hiện đại, chưa đủ độ 'đã' về mặt kỹ thuật truyền thống."
    },
    {
      "leftId": "dt_01_concept_03",
      "rightId": "dt_01_concept_05",
      "winnerId": "dt_01_concept_05",
      "reason": "Concept 05 giải quyết được 'điểm nghẽn' lớn nhất của ngư dân thời đó là bảo quản đá lạnh. Cơ chế xây hầm đá bằng trấu/xơ dừa rất thông minh, đậm chất Việt Nam và tạo ra lợi thế kinh tế rõ rệt cho cả làng, quy mô phát triển 30 chương tiềm năng hơn việc chỉ sửa lưới."
    },
    {
      "leftId": "dt_01_concept_03",
      "rightId": "dt_01_concept_06",
      "winnerId": "dt_01_concept_06",
      "reason": "Concept 06 về cải tạo tàu thuyền có sức nặng hơn về mặt 'agency' của nhân vật chính. Việc thay đổi cấu trúc mũi thuyền để tiết kiệm dầu là một bài toán kỹ thuật thú vị, mang lại lợi ích kinh tế trực tiếp và lâu dài hơn là sửa lưới."
    },
    {
      "leftId": "dt_01_concept_03",
      "rightId": "dt_01_concept_07",
      "winnerId": "dt_01_concept_03",
      "reason": "Concept 03 thắng vì tính cấp thiết của công cụ sản xuất. Trong bối cảnh nghèo khó, việc sửa được tấm lưới để đi biển quan trọng hơn việc nâng cấp chất lượng ruốc sấy (vốn phụ thuộc vào thị trường ngách)."
    },
    {
      "leftId": "dt_01_concept_03",
      "rightId": "dt_01_concept_08",
      "winnerId": "dt_01_concept_03",
      "reason": "Concept 03 dựa hoàn toàn vào tay nghề cơ khí, trong khi 08 dựa trên ký ức về vị trí bãi sò (gần ranh giới 'tọa độ chính xác'). 03 tạo ra sự chủ động và bền vững hơn trong việc xây dựng uy tín từ kỹ năng."
    },
    {
      "leftId": "dt_01_concept_03",
      "rightId": "dt_01_concept_09",
      "winnerId": "dt_01_concept_03",
      "reason": "Sửa lưới (03) là hành động trực tiếp cứu vãn sinh kế biển, khớp với yêu cầu 'biến hiểu biết thành dụng cụ'. Làm muối (09) có nhịp độ chậm và ít biến hóa về mặt kỹ thuật hơn trong 30 chương."
    },
    {
      "leftId": "dt_01_concept_03",
      "rightId": "dt_01_concept_10",
      "winnerId": "dt_01_concept_03",
      "reason": "Concept 03 là nam tần tay nghề điển hình, giải quyết khó khăn bằng lao động và trí tuệ kỹ thuật. Concept 10 quá thiên về dịch vụ, không tạo ra cảm giác 'làm giàu từ biển' mạnh mẽ như 03."
    },
    {
      "leftId": "dt_01_concept_04",
      "rightId": "dt_01_concept_05",
      "winnerId": "dt_01_concept_05",
      "reason": "Concept 05 vượt trội nhờ đánh đúng vào thực tế logistics của huyện biển những năm 80. Việc giữ lạnh cá tôm có tác động kinh tế lớn hơn nhiều so với việc khai thác rong biển vốn chưa có thị trường tiêu thụ rộng rãi."
    },
    {
      "leftId": "dt_01_concept_04",
      "rightId": "dt_01_concept_06",
      "winnerId": "dt_01_concept_06",
      "reason": "Cải tạo thuyền (06) là một kỹ năng cốt lõi trong nghề biển, tạo ra vòng lặp thưởng (tiết kiệm dầu -> tăng lãi) rất rõ ràng. Rong biển (04) gặp rào cản lớn về định kiến thực phẩm, khó tạo ra thành quả sớm trong 3 chương đầu."
    },
    {
      "leftId": "dt_01_concept_04",
      "rightId": "dt_01_concept_07",
      "winnerId": "dt_01_concept_07",
      "reason": "Concept 07 về ruốc sấy thực tế hơn với đời sống Việt Nam. Con moi/ruốc là sản vật phổ biến, việc nâng cấp quy trình sấy sạch tạo ra giá trị gia tăng dễ chấp nhận hơn là ăn rong biển."
    },
    {
      "leftId": "dt_01_concept_04",
      "rightId": "dt_01_concept_08",
      "winnerId": "dt_01_concept_08",
      "reason": "Concept 08 có xung đột cộng đồng và bài toán bền vững (chương 21-30) rất tốt. Việc tìm lại bãi sò huyết mang tính biểu tượng cho sự hồi sinh của làng chài mạnh hơn là khai thác rong biển."
    },
    {
      "leftId": "dt_01_concept_04",
      "rightId": "dt_01_concept_09",
      "winnerId": "dt_01_concept_09",
      "reason": "Muối (09) là nguyên liệu thiết yếu cho mọi hoạt động chế biến hải sản (mắm, cá khô). Concept 09 tạo ra một hệ sinh thái hỗ trợ các nghề khác tốt hơn là hướng đi đơn độc của rong biển (04)."
    },
    {
      "leftId": "dt_01_concept_04",
      "rightId": "dt_01_concept_10",
      "winnerId": "dt_01_concept_04",
      "reason": "Dù rong biển (04) khó khăn nhưng vẫn là sản xuất thực tế. Concept 10 quá mơ mộng so với bối cảnh kinh tế những năm 1980, khó thuyết phục được độc giả về tính khả thi của việc kiếm tiền từ kể chuyện."
    },
    {
      "leftId": "dt_01_concept_05",
      "rightId": "dt_01_concept_06",
      "winnerId": "dt_01_concept_05",
      "reason": "Cả hai đều xuất sắc, nhưng 05 thắng vì giải quyết được mâu thuẫn với thương lái (ép giá do cá ươn) - một yếu tố kinh điển trong truyện làm giàu. Cơ chế giữ lạnh bằng vật liệu tự nhiên rất sáng tạo và thực dụng."
    },
    {
      "leftId": "dt_01_concept_05",
      "rightId": "dt_01_concept_07",
      "winnerId": "dt_01_concept_05",
      "reason": "Concept 05 tạo ra một hạ tầng (giữ lạnh) cho toàn bộ sản lượng của làng, trong khi 07 chỉ tập trung vào một loại hải sản. Tầm ảnh hưởng và khả năng mở rộng quan hệ của 05 mạnh hơn."
    },
    {
      "leftId": "dt_01_concept_05",
      "rightId": "dt_01_concept_08",
      "winnerId": "dt_01_concept_05",
      "reason": "Concept 05 thể hiện agency của nhân vật qua việc xây dựng hệ thống kỹ thuật. Concept 08 dù tốt nhưng phần nào vẫn dựa vào sự 'may mắn' khi tìm thấy bãi sò, không thể hiện rõ tính 'kỹ sư' như 05."
    },
    {
      "leftId": "dt_01_concept_05",
      "rightId": "dt_01_concept_09",
      "winnerId": "dt_01_concept_05",
      "reason": "Nước đá (05) là một cuộc cách mạng cho bảo quản hải sản tươi sống, mang lại lợi nhuận đột biến hơn so với việc tối ưu hóa hạt muối (09). 05 cũng tạo ra sự đối đầu rõ nét với các chủ vựa."
    },
    {
      "leftId": "dt_01_concept_05",
      "rightId": "dt_01_concept_10",
      "winnerId": "dt_01_concept_05",
      "reason": "Concept 05 hoàn toàn áp đảo về tính thực tế, cơ chế vòng thưởng và sự phù hợp với đối tượng độc giả thích làm giàu bằng tay nghề thực thụ thay vì làm dịch vụ văn hóa."
    }
  ]
}
